function getRandomGenchemExemplars(count = 3) {
  if (genchemExemplars.length <= count) {
    return [...genchemExemplars].sort(() => 0.5 - Math.random());
  }
  const shuffled = [...genchemExemplars].sort(() => 0.5 - Math.random());
  return shuffled.slice(0, count);
}

function formatGenchemExemplars(exemplars) {
  return exemplars.map((ex, index) => {
    // Determine the label
    let label = "USNCO Example";
    if (ex.id === "genchem_ex3") {
      label = "IChO Example (free_response)";
    } else if (ex.id === "chem_ex2") {
      label = "SVG Titration Curve Exemplar (free_response with SVG diagram)";
    } else if (ex.qtype === "multiple_choice") {
      label = "USNCO Example (multiple_choice)";
    } else if (ex.qtype === "free_response") {
      label = "USNCO Example (free_response)";
    }
    
    // Create copy without id to mimic original structure
    const clone = { ...ex };
    delete clone.id;
    
    return `${label}:\n${JSON.stringify(clone, null, 2)}`;
  }).join('\n\n');
}

console.log("Formatting check:");
console.log(formatGenchemExemplars(getRandomGenchemExemplars(3)));
